# HEADER
h1, h2, h3 = st.columns([4, 1.2, 0.3])
with h1:
    st.markdown('<a href="/" target="_self" class="propiq-logo">PROP<span>IQ</span></a><div class="propiq-tagline">Know before you buy</div>', unsafe_allow_html=True)
with h2:
    st.selectbox("", list(LANGS.keys()), key="lang_label", label_visibility="collapsed")
with h3:
    st.page_link("pages/admin.py", label="👤", use_container_width=True)

lang = LANGS[st.session_state["lang_label"]]
st.markdown("<hr style='border:none;border-top:1px solid #ede8de;margin:16px 0 24px'>", unsafe_allow_html=True)

# ══════════════════════════════════════
# STEP 0 — PROPERTY FORM
# ══════════════════════════════════════
if st.session_state.step == 0:
    col_form, col_help = st.columns([3,2], gap="large")
    with col_form:
        st.markdown(f'<div class="section-label">{T[lang]["prop_details"]}</div>', unsafe_allow_html=True)
        with st.form("property_form"):
            address = st.text_input(T[lang]["address_label"], placeholder=T[lang]["address_ph"])
            c1, c2 = st.columns(2)
            with c1:
                district = st.selectbox(T[lang]["district"], ["Dubai Marina","Downtown Dubai","Business Bay","Palm Jumeirah","JVC","JBR","DIFC","Arabian Ranches","Creek Harbour","MBR City"])
                asking_price = st.number_input(T[lang]["price"], min_value=200000, max_value=100000000, value=1500000, step=50000)
                area_sqft = st.number_input(T[lang]["area"], min_value=100, max_value=20000, value=900)
            with c2:
                property_type = st.selectbox(T[lang]["prop_type"], T[lang]["prop_types"])
                default_rent = int(DLD_RENTS.get(district, 90000)) if district else 90000
                avg_rent = st.number_input(T[lang]["avg_rent"], min_value=10000, max_value=2000000, value=default_rent, step=5000)
                project_completion = st.slider(T[lang]["completion"], 0, 100, 100)
            default_tx = int(DLD_TX_COUNTS.get(district, 35)) if district else 35
            default_tx = max(1, min(150, default_tx))
            transactions_90d = st.slider(T[lang]["transactions"], 1, 150, default_tx)
            st.markdown("<br>", unsafe_allow_html=True)
            go = st.form_submit_button(T[lang]["get_score"], use_container_width=True, type="primary")

        if go:
            if not address:
                st.error(T[lang]["err_address"])
            else:
                benchmarks = DLD_BENCHMARKS
                benchmark = benchmarks.get(district, 1100)
                price_sqft = asking_price / area_sqft
                gross_yield = (avg_rent / asking_price) * 100
                dev = (price_sqft - benchmark) / benchmark * 100
                scores = {}
                details = {}
                if gross_yield >= 8: scores["yield"]=20; details["yield"]=f"Excellent yield {gross_yield:.1f}%"
                elif gross_yield >= 6.5: scores["yield"]=17; details["yield"]=f"Good yield {gross_yield:.1f}%"
                elif gross_yield >= 5.5: scores["yield"]=13; details["yield"]=f"Average yield {gross_yield:.1f}%"
                elif gross_yield >= 4.5: scores["yield"]=8; details["yield"]=f"Below average {gross_yield:.1f}%"
                else: scores["yield"]=3; details["yield"]=f"Low yield {gross_yield:.1f}%"
                if dev<=-10: scores["price"]=20; details["price"]=f"{abs(dev):.0f}% below market — great price"
                elif dev<=-5: scores["price"]=17; details["price"]=f"{abs(dev):.0f}% below market"
                elif dev<=0: scores["price"]=14; details["price"]="At market price"
                elif dev<=5: scores["price"]=10; details["price"]=f"+{dev:.0f}% above market"
                elif dev<=15: scores["price"]=5; details["price"]=f"+{dev:.0f}% above market — negotiate"
                else: scores["price"]=0; details["price"]=f"+{dev:.0f}% — overpriced"
                if transactions_90d>=80: scores["liq"]=20; details["liq"]=f"{transactions_90d} deals — high liquidity"
                elif transactions_90d>=50: scores["liq"]=16; details["liq"]=f"{transactions_90d} deals — good liquidity"
                elif transactions_90d>=25: scores["liq"]=12; details["liq"]=f"{transactions_90d} deals — average"
                elif transactions_90d>=10: scores["liq"]=7; details["liq"]=f"{transactions_90d} deals — low liquidity"
                else: scores["liq"]=3; details["liq"]=f"{transactions_90d} deals — risk"
                if project_completion==100: scores["dev"]=20; details["dev"]="Ready — no construction risk"
                elif project_completion>=80: scores["dev"]=17; details["dev"]=f"{project_completion}% — minimal risk"
                elif project_completion>=60: scores["dev"]=13; details["dev"]=f"{project_completion}% — moderate risk"
                elif project_completion>=30: scores["dev"]=8; details["dev"]=f"{project_completion}% — delay risk"
                else: scores["dev"]=4; details["dev"]=f"{project_completion}% — high risk"
                scores["momentum"]=15; details["momentum"]="Dubai market stable 2026"
                total = sum(scores.values())
                if total>=85: vt,vc="Buy now","#2d7a4f"
                elif total>=70: vt,vc="Good deal","#2d7a4f"
                elif total>=55: vt,vc="Fair price","#c9a84c"
                elif total>=40: vt,vc="Caution","#e07b2a"
                else: vt,vc="Unfavorable","#c0392b"
                st.session_state.calc = {"scores":scores,"details":details,"total":total,"gross_yield":round(gross_yield,1),"price_sqft":round(price_sqft),"benchmark":benchmark,"vt":vt,"vc":vc,"address":address,"district":district,"asking_price":asking_price,"avg_rent":avg_rent}
                st.session_state.step = 1
                st.rerun()

    with col_help:
        st.markdown(f'<div class="section-label">{T[lang]["how_to_fill"]}</div>', unsafe_allow_html=True)
        for title, text in [
            (T[lang]["h_address"], T[lang]["h_address_t"]),
            (T[lang]["h_price"],   T[lang]["h_price_t"]),
            (T[lang]["h_rent"],    T[lang]["h_rent_t"]),
            (T[lang]["h_tx"],      T[lang]["h_tx_t"]),
        ]:
            st.markdown(f'<div class="help-card"><div class="help-title">{title}</div><div class="help-text">{text}</div></div>', unsafe_allow_html=True)

